mapper.select:
select ifnull(sum(pay_amount), 0)
from t_order
where status in (1, 2, 3)
  and pay_time is not null
  and pay_time >= #{startTime}
  and pay_time < #{endTimeExclusive}

select count(1)
from t_order
where create_time >= #{startTime}
  and create_time < #{endTimeExclusive}

select count(1)
from t_order
where status in (1, 2, 3)
  and pay_time is not null
  and pay_time >= #{startTime}
  and pay_time < #{endTimeExclusive}

select count(1)
from t_wxuser
where create_time >= #{startTime}
  and create_time < #{endTimeExclusive}

select count(1)
from t_marketing_activity
where status = 1
  and end_time is not null
  and end_time >= #{nowTime}
  and end_time < #{endingSoonTime}
